package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

public class CSVFormatTest {

    @Test
    public void testWithTrailingDelimiter() {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set up the expected behavior
        when(csvFormat.withTrailingDelimiter()).thenReturn(csvFormat);

        // Perform the method invocation
        CSVFormat result = csvFormat.withTrailingDelimiter();

        // Verify the result
        assertEquals(csvFormat, result);
        verify(csvFormat, times(1)).withTrailingDelimiter();
    }
}
